import { Link, useNavigate, useLocation } from 'react-router-dom';
import { useAuth } from '../context/AuthContext';

const Navbar = () => {
  const { user, logout } = useAuth();
  const navigate = useNavigate();
  const location = useLocation();

  const handleLogout = () => {
    logout();
    navigate('/login');
  };

  // 如果在登入或註冊頁面，隱藏 Navbar 以保持 APP 登入頁的純淨感
  if (location.pathname === '/login' || location.pathname === '/register') return null;

  return (
    <div className="fixed top-0 left-0 right-0 z-50 flex justify-center">
      {/* 限制寬度與頁面容器一致 */}
      <nav className="w-full max-w-[420px] bg-white border-b border-gray-100 px-6 py-4 flex justify-between items-center shadow-sm backdrop-blur-md bg-white/90">

        {/* 左側標題：點擊回首頁 */}
        <Link to="/" className="text-xl font-black text-indigo-900 tracking-tight">
          Sam's App
        </Link>

        {/* 右側按鈕群 */}
        <div className="flex items-center space-x-4">
          {user ? (
            <>
              {/* 管理按鈕：改用小圖示風格 */}
              <Link 
                to="/manage-tours" 
                className={`text-xl ${location.pathname === '/manage-tours' ? 'text-emerald-500' : 'text-gray-400'}`}
              >
                ⚙️
              </Link>

              {/* 登出按鈕 */}
              <button
                onClick={handleLogout}
                className="text-xs font-bold text-red-400 uppercase tracking-tighter"
              >
                Logout
              </button>

              {/* 頭像 */}
              <div className="w-8 h-8 bg-indigo-50 rounded-full border border-gray-100 overflow-hidden">
                <img src={`https://api.dicebear.com/7.x/avataaars/svg?seed=${user.username}`} alt="avatar" />
              </div>
            </>
          ) : (
            <Link to="/login" className="text-sm font-bold text-indigo-600">Login</Link>
          )}
        </div>
      </nav>
    </div>
  );
};

export default Navbar;
